// 🤖 Therapist-style AI Replies Engine

// Crisis reply (keep this — improved but safe)
export const crisisReply = () => {
  const replies = [
    "I’m really glad you told me 💙 What you’re feeling is heavy, but you are not alone. Your life matters deeply.",
    "I hear you 😔 This sounds overwhelming right now. Please pause with me — help and care are around you.",
    "Thank you for opening up 💙 Even though this moment feels unbearable, it does not define you or your future.",
    "I’m here with you 🤍 You don’t have to face this alone. Let’s take this one breath at a time."
  ];

  return replies[Math.floor(Math.random() * replies.length)];
};

// 🌱 Normal therapist conversation replies
export const getTherapistReply = (mood, intent) => {
  // 🎭 Mood-based responses
  const moodReplies = {
    anxious: [
      "I hear you 💙 It sounds like you’re feeling quite anxious and overwhelmed.",
      "That makes sense 🤍 Anxiety can really take over when there’s a lot on your mind."
    ],
    sad: [
      "I’m really glad you shared this with me 💙 It sounds like you’re feeling low.",
      "That sounds heavy 😔 Feeling this way can be very exhausting."
    ],
    angry: [
      "I hear a lot of frustration in what you’re saying 😤",
      "That sounds really upsetting. Anyone in your place might feel angry."
    ],
    happy: [
      "That’s lovely to hear 😊 It sounds like something positive is going on for you.",
      "I can sense some happiness there 🌸"
    ],
    calm: [
      "That sounds peaceful 🤍",
      "It’s nice to hear you’re feeling balanced."
    ],
    neutral: [
      "I’m listening 💭",
      "Tell me more — I’m here with you."
    ]
  };

  const baseReply =
    moodReplies[mood]?.[
      Math.floor(Math.random() * moodReplies[mood].length)
    ] || "I’m here and listening 💙";

  // 🧠 Intent-based continuation
  if (intent === "wantsAdvice") {
    return (
      baseReply +
      " Before I suggest anything, would you like some guidance or would you prefer to talk more about it first?"
    );
  }

  if (intent === "wantsToVent") {
    return (
      baseReply +
      " Take your time — you can tell me whatever feels important right now."
    );
  }

  if (intent === "wantsSongs") {
    return (
      baseReply +
      " Music can really help with emotions 🎵 What kind of songs do you feel like listening to right now — calming, uplifting, or comforting?"
    );
  }

  // Default gentle follow-up (MOST IMPORTANT PART)
  return (
    baseReply +
    " Would you like to tell me what’s been triggering these feelings lately?"
  );
};
